#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<vector<long long>> rows;
    rows.reserve(n);
    for(int i=0;i<n;++i){
        vector<long long> row;
        if(i==0){
            row.push_back(1);
        }else{
            const vector<long long>& prev = rows.back();
            row.push_back(1);
            for(size_t j=1;j<prev.size();++j){
                row.push_back(prev[j-1]+prev[j]);
            }
            row.push_back(1);
        }
        rows.push_back(row);
        for(size_t j=0;j<row.size();++j){
            if(j) cout<<' ';
            cout<<row[j];
        }
        if(i!=n-1) cout<<'\n';
    }
    return 0;
}
